// src/components/CategoryItem/index.jsx

import React from 'react';
import { Link } from 'react-router-dom';
import s from './CategoryItem.module.css';

// Компонент теперь должен принимать локально импортированный URL в пропсе 'image'
const CategoryItem = ({ id, title, image }) => {
  return (
    <Link to={`/categories/${id}`} className={s.cardLink}>
      <div className={s.categoryCard}>
        {/* URL изображения приходит из STATIC_CATEGORIES в MainPage */}
        <img src={image} alt={title} className={s.image} /> 

        {/* Текст категории */}
        <p className={s.title}>{title}</p>
      </div>
    </Link>
  );
};

export default CategoryItem;
